 // Importando a lógica

'use client';
import React, { useState, useEffect } from 'react';
import { buscarOfertasPromocao } from "./ofertasService";
import '../App.css';

export default function Topo({ totalItens, abrirCarrinho, verHistorico, usuarioLogado, setProdutos }) {
  const [tempo, setTempo] = useState(86400); // 24 horas

  // Lógica do Timer
  useEffect(() => {
    const timer = setInterval(() => {
      setTempo(prev => (prev > 0 ? prev - 1 : 86400));
    }, 1000);
    return () => clearInterval(timer);
  }, []);

  const formatarTempo = (segundos) => {
    const h = Math.floor(segundos / 3600);
    const m = Math.floor((segundos % 3600) / 60);
    const s = segundos % 60;
    const format = (num) => String(num).padStart(2, '0');
    return `${format(h)}h ${format(m)}m ${format(s)}s`;
  };

  // Lógica para carregar a VIEW do MySQL
  const lidarComOfertas = async () => {
    const ofertas = await buscarOfertasPromocao();
    if (ofertas && ofertas.length > 0) {
      // Atualiza o estado global de produtos com os dados da VIEW promocao_10
      setProdutos(ofertas);
    } else {
      alert("Nenhuma oferta de Mercearia disponível no momento.");
    }
  };

  return (
    <header className="topo-container">
      <img src="slog.png" alt="Logo" className="imagem-topo" style={{ height: '100px' }} />

      <div className="topo-centro">
        <h1>Amigo do Bairro</h1>
        <div className="ofertas-timer">
          🔥 OFERTAS DA SEMANA: {formatarTempo(tempo)} 🔥
        </div>
      </div>

      <div className="header-actions">
        {/* Botão de Ofertas (Mercearia 10%) */}
        <button className="btn-promocao" onClick={lidarComOfertas}>
          🏷️ Mercearia 10% OFF
        </button>

        {/* Botão do Carrinho */}
        <button onClick={abrirCarrinho} className="botao-carrinho">
          🛒 <span className="badge">Carrinho</span>
          <span> ({totalItens})</span>
        </button>

        {/* Botão de Histórico / Usuário */}
        <button className="btn-historico" onClick={verHistorico} style={{ cursor: 'pointer' }}>
          {usuarioLogado ? `Olá, 👤 ${usuarioLogado.nome}` : "📋 Meus Pedidos"}
        </button>
      </div>
    </header>
  );
}
